-- startup-service/seed.sql
-- Table: startups
-- Startup IDs: auto-increment (MySQL assigns 1,2,3... → deterministic via ORDER)
--   We fix startup IDs 2001–2100 by using INSERT with explicit id overrides.
--   Note: table uses IDENTITY, but for seeding we provide explicit IDs so
--   cross-service references (team-service, investment-service) remain stable.
-- Founder IDs: 1001–1060 (FOUNDER role users from auth/user-service)
-- Stages: IDEA, MVP, EARLY_TRACTION, SCALING
-- Idempotent: INSERT IGNORE
-- =============================================================================

SET NAMES utf8mb4;
SET foreign_key_checks = 0;

-- Allow explicit ID insertion even though IDENTITY strategy is used
-- (MySQL: insert with explicit PK works; JPA won't re-insert via INSERT IGNORE)

